import React from 'react'
import { Link } from 'react-router-dom'
import styled from 'styled-components'

const BreadcrumbContainer = styled.div(
  ({ theme: { color } }) => `
  margin-top: 2rem;
  margin-bottom: 2rem;
  a,
  p {
    color: ${color.secondaryText};
    text-transform: lowercase;
  }
`
)

const LinkText = styled.p`
  display: inline-block;
  text-decoration: underline;
`

const PlainText = styled.p`
  display: inline;
  font-weight: lighter;
`

const Separator = styled.span`
  margin: 0 0.5rem;
`

interface BreadcrumbProps {
  items: {
    label: string
    path?: string
  }[]
}

export const Breadcrumb = ({ items }: BreadcrumbProps) => {
  return (
    <BreadcrumbContainer>
      {items.map((item, index) => (
        <React.Fragment key={index}>
          {index > 0 && <Separator>/</Separator>}
          {item.path ? (
            <LinkText>
              <Link to={item.path}>{item.label}</Link>
            </LinkText>
          ) : (
            <PlainText>{item.label}</PlainText>
          )}
        </React.Fragment>
      ))}
    </BreadcrumbContainer>
  )
}

import * as React from 'react'
import { CSSTransition } from 'react-transition-group'

import { Portal } from '../Portal'
import { useKey } from '../../hooks/useKeyboard'
import { Button } from '../Button'
import { useLockBodyScroll } from '../../hooks/useBodyScrollLock'

import { ModalContent, TopBar, Backdrop } from './Modal.styles'

type ModalProps = {
  isOpen: boolean
  onClose: () => void
}

export const Modal: React.FC<React.PropsWithChildren<ModalProps>> = ({
  children,
  isOpen,
  onClose,
}) => {
  useKey('escape', onClose)
  useLockBodyScroll(isOpen)
  const contentRef = React.useRef(null)
  const backdropRef = React.useRef(null)

  return (
    <Portal selector="#modal">
      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="modal"
        unmountOnExit
        nodeRef={contentRef}
      >
        <ModalContent data-testid="modal" ref={contentRef}>
          <TopBar>
            <Button
              data-testid="modal-close-btn"
              onClick={onClose}
              clear
              round
              icon="cross"
              aria-label="close modal"
              iconSize={16}
            />
          </TopBar>
          {children}
        </ModalContent>
      </CSSTransition>

      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="backdrop"
        unmountOnExit
        nodeRef={backdropRef}
      >
        <Backdrop data-testid="modal-backdrop" ref={backdropRef} onClick={onClose} />
      </CSSTransition>
    </Portal>
  )
}

